  1	import {
  2	  Divider,
  3	  DrawerActions,
  4	  DrawerCloseButton,
  5	  DrawerHead,
  6	  DrawerPanelBody,
  7	  DrawerPanelContent,
  8	  Tab,
  9	  Tabs,
 10	  TabTitleText,
 11	  Text,
 12	  TextVariants
 13	} from '@patternfly/react-core';
 14	import { BaseEdge } from '@patternfly/react-topology';
 15	import _ from 'lodash';
 16	import * as React from 'react';
 17	import { useTranslation } from 'react-i18next';
 18	import { TopologyMetrics } from '../../../api/loki';
 19	import { RuleDetails } from '../../../components/health/rule-details';
 20	import { Filter, FilterDefinition, Filters } from '../../../model/filters';
 21	import { MetricType } from '../../../model/flow-query';
 22	import { GraphElementPeer, NodeData } from '../../../model/topology';
 23	import { defaultSize, maxSize, minSize } from '../../../utils/panel';
 24	import { TruncateLength } from '../../dropdowns/truncate-dropdown';
 25	import { HealthCard } from '../../health/health-card';
 26	import { HealthSuperKind } from '../../health/health-helper';
 27	import { PeerResourceLink } from '../../tabs/netflow-topology/peer-resource-link';
 28	import { ElementPanelContent } from './element-panel-content';
 29	import { ElementPanelMetrics } from './element-panel-metrics';
 30	import './element-panel.css';
 31	
 32	export interface ElementPanelProps {
 33	  onClose: () => void;
 34	  element: GraphElementPeer;
 35	  metrics: TopologyMetrics[];
 36	  droppedMetrics: TopologyMetrics[];
 37	  metricType: MetricType;
 38	  filters: Filters;
 39	  filterDefinitions: FilterDefinition[];
 40	  setFilters: (filters: Filter[]) => void;
 41	  truncateLength: TruncateLength;
 42	  id?: string;
 43	  isDark?: boolean;
 44	}
 45	
 46	export const ElementPanel: React.FC<ElementPanelProps> = ({
 47	  id,
 48	  element,
 49	  metrics,
 50	  droppedMetrics,
 51	  metricType,
 52	  filters,
 53	  filterDefinitions,
 54	  setFilters,
 55	  onClose,
 56	  truncateLength,
 57	  isDark
 58	}) => {
 59	  const { t } = useTranslation('plugin__netobserv-plugin');
 60	  const [activeTab, setActiveTab] = React.useState<string>('details');
 61	
 62	  const data = element.getData();
 63	  const noMetrics = data && data.noMetrics === true;
 64	  let aData: NodeData;
 65	  let bData: NodeData | undefined;
 66	  if (element instanceof BaseEdge) {
 67	    aData = element.getSource().getData();
 68	    bData = element.getTarget().getData();
 69	  } else {
 70	    aData = data!;
 71	  }
 72	
 73	  // Get the element panel display name to compare with card names
 74	  const elementName = React.useMemo(() => {
 75	    if (element instanceof BaseEdge) {
 76	      return undefined;
 77	    } else {
 78	      return data?.peer.getDisplayName(false, false);
 79	    }
 80	  }, [element, data]);
 81	
 82	  const healthKind: HealthSuperKind | undefined = React.useMemo(() => {
 83	    const nodeType = data?.nodeType;
 84	    if (nodeType === 'host') {
 85	      return 'Node';
 86	    } else if (nodeType === 'namespace') {
 87	      return 'Namespace';
 88	    } else if (nodeType === 'owner') {
 89	      return 'Owner';
 90	    }
 91	    return undefined;
 92	  }, [data]);
 93	
 94	  const titleContent = React.useCallback(() => {
 95	    if (element instanceof BaseEdge) {
 96	      return <Text component={TextVariants.h2}>{t('Edge')}</Text>;
 97	    } else {
 98	      if (data && elementName) {
 99	        return <PeerResourceLink peer={data.peer} />;
100	      }
101	      return <Text component={TextVariants.h2}>{t('Unknown')}</Text>;
102	    }
103	  }, [element, elementName, data, t]);
104	
105	  React.useEffect(() => {
106	    if ((activeTab === 'metrics' && _.isEmpty(metrics)) || (activeTab === 'dropped' && _.isEmpty(droppedMetrics))) {
107	      setActiveTab('details');
108	    }
109	  }, [metrics, droppedMetrics, activeTab]);
110	
111	  React.useEffect(() => {
112	    if (activeTab === 'health' && _.isEmpty(data?.health)) {
113	      setActiveTab('details');
114	    }
115	  }, [activeTab, data?.health]);
116	
117	  return (
118	    <DrawerPanelContent
119	      data-test-id={id}
120	      id={id}
121	      className="drawer-panel-content"
122	      isResizable
123	      defaultSize={defaultSize}
124	      minSize={minSize}
125	      maxSize={maxSize}
126	    >
127	      <DrawerHead id={`${id}-drawer-head`} data-test-id="drawer-head" className="drawer-head">
128	        {titleContent()}
129	        <DrawerActions>
130	          <DrawerCloseButton data-test-id="drawer-close-button" className="drawer-close-button" onClick={onClose} />
131	        </DrawerActions>
132	      </DrawerHead>
133	      <Divider />
134	      <DrawerPanelBody id={`${id}-drawer-body`} className="drawer-body" data-test-id="drawer-body">
135	        <Tabs
136	          id="drawer-tabs"
137	          activeKey={activeTab}
138	          usePageInsets
139	          onSelect={(e, key) => setActiveTab(key as string)}
140	          role="region"
141	        >
142	          <Tab className="drawer-tab" eventKey={'details'} title={<TabTitleText>{t('Details')}</TabTitleText>}>
143	            <ElementPanelContent
144	              element={element}
145	              filters={filters}
146	              setFilters={setFilters}
147	              filterDefinitions={filterDefinitions}
148	            />
149	          </Tab>
150	          {!noMetrics && !_.isEmpty(metrics) && (
151	            <Tab className="drawer-tab" eventKey={'metrics'} title={<TabTitleText>{t('Metrics')}</TabTitleText>}>
152	              <ElementPanelMetrics
153	                aData={aData}
154	                bData={bData}
155	                isGroup={element.getType() === 'group'}
156	                metrics={metrics}
157	                metricType={metricType}
158	                truncateLength={truncateLength}
159	              />
160	            </Tab>
161	          )}
162	          {!noMetrics && !_.isEmpty(droppedMetrics) && (
163	            <Tab className="drawer-tab" eventKey={'dropped'} title={<TabTitleText>{t('Drops')}</TabTitleText>}>
164	              <ElementPanelMetrics
165	                aData={aData}
166	                bData={bData}
167	                isGroup={element.getType() === 'group'}
168	                metrics={droppedMetrics}
169	                metricType={metricType}
170	                truncateLength={truncateLength}
171	              />
172	            </Tab>
173	          )}
174	          {data?.health !== undefined && healthKind !== undefined && (
175	            <Tab className="drawer-tab" eventKey={'health'} title={<TabTitleText>{t('Health')}</TabTitleText>}>
176	              <>
177	                <HealthCard
178	                  key={`card-${data.health.name}`}
179	                  resourceHealth={data.health}
180	                  name={data.health.name}
181	                  k8sKind={data.health.k8sKind}
182	                  isDark={isDark || false}
183	                  isSelected={true}
184	                  hideTitle={true}
185	                />
186	                <div className="health-details">
187	                  <RuleDetails kind={healthKind} resourceHealth={data.health} />
188	                </div>
189	              </>
190	            </Tab>
191	          )}
192	        </Tabs>
193	      </DrawerPanelBody>
194	    </DrawerPanelContent>
195	  );
196	};
197	
198	export default ElementPanel;

