  1	import { Drawer, DrawerContent } from '@patternfly/react-core';
  2	import { BaseEdge, BaseNode, NodeModel } from '@patternfly/react-topology';
  3	import { fireEvent, render, waitFor } from '@testing-library/react';
  4	import * as React from 'react';
  5	
  6	import { TopologyMetrics } from '../../../../api/loki';
  7	import { Filters } from '../../../../model/filters';
  8	import { FlowScope, MetricType } from '../../../../model/flow-query';
  9	import { NodeData } from '../../../../model/topology';
 10	import { createPeer } from '../../../../utils/metrics';
 11	import { FilterDefinitionSample } from '../../../__tests-data__/filters';
 12	import { TruncateLength } from '../../../dropdowns/truncate-dropdown';
 13	import { dataSample } from '../../../tabs/netflow-topology/__tests-data__/metrics';
 14	import { ElementPanel } from '../element-panel';
 15	import { ElementPanelContent } from '../element-panel-content';
 16	import { ElementPanelMetrics } from '../element-panel-metrics';
 17	
 18	describe('<ElementPanel />', () => {
 19	  const getNode = (kind: string, name: string, addr: string) => {
 20	    const bn = new BaseNode<NodeModel, NodeData>();
 21	    bn.setData({
 22	      nodeType: 'resource',
 23	      peer: createPeer({
 24	        addr: addr,
 25	        resource: { name, type: kind }
 26	      })
 27	    });
 28	    return bn;
 29	  };
 30	
 31	  const getEdge = () => {
 32	    const be = new BaseEdge();
 33	    be.setSource(getNode('Pod', 'flowlogs-pipeline-69b6669d59-f76sh', '10.131.0.18'));
 34	    be.setTarget(getNode('Service', 'dns-default', '172.30.0.10'));
 35	    return be;
 36	  };
 37	
 38	  const mocks = {
 39	    element: getNode('Pod', 'loki-distributor-loki-76598c8449-csmh2', '10.129.0.15'),
 40	    metrics: dataSample as TopologyMetrics[],
 41	    droppedMetrics: [],
 42	    metricType: 'Bytes' as MetricType,
 43	    metricScope: 'resource' as FlowScope,
 44	    filters: { list: [], match: 'all' } as Filters,
 45	    filterDefinitions: FilterDefinitionSample,
 46	    setFilters: jest.fn(),
 47	    onClose: jest.fn(),
 48	    truncateLength: TruncateLength.M,
 49	    id: 'element-panel-test'
 50	  };
 51	
 52	  it('should render component', async () => {
 53	    const { container } = render(<ElementPanel {...mocks} />);
 54	    expect(container.querySelector('#element-panel-test')).toBeTruthy();
 55	  });
 56	
 57	  it('should close on click', async () => {
 58	    render(
 59	      <Drawer isExpanded>
 60	        <DrawerContent panelContent={<ElementPanel {...mocks} />}>
 61	          <div />
 62	        </DrawerContent>
 63	      </Drawer>
 64	    );
 65	    await waitFor(() => {
 66	      expect(document.querySelector('[data-test-id="drawer-close-button"]')).toBeTruthy();
 67	    });
 68	    fireEvent.click(document.querySelector('[data-test-id="drawer-close-button"]')!);
 69	    expect(mocks.onClose).toHaveBeenCalled();
 70	  });
 71	
 72	  it('should render element details', async () => {
 73	    const { container, rerender } = render(<ElementPanelContent {...mocks} />);
 74	    await waitFor(() => {
 75	      expect(container.querySelector('#node-info-address')).toBeTruthy();
 76	    });
 77	    expect(container.querySelector('#node-info-address')?.textContent).toContain('10.129.0.15');
 78	
 79	    rerender(<ElementPanelContent {...mocks} element={getEdge()} />);
 80	    await waitFor(() => {
 81	      expect(container.querySelector('#source-content')).toBeTruthy();
 82	    });
 83	    expect(container.querySelector('#source-content')?.textContent).toContain('10.131.0.18');
 84	    expect(container.querySelector('#destination-content')?.textContent).toContain('172.30.0.10');
 85	  });
 86	
 87	  it('should render node metrics', async () => {
 88	    const { container } = render(
 89	      <ElementPanelMetrics
 90	        metricType={mocks.metricType}
 91	        metrics={mocks.metrics}
 92	        aData={mocks.element.getData()!}
 93	        truncateLength={TruncateLength.M}
 94	        isGroup={false}
 95	      />
 96	    );
 97	    await waitFor(() => {
 98	      expect(container.querySelector('#metrics-stats-total-in')).toBeTruthy();
 99	    });
100	    expect(container.querySelector('#metrics-stats-total-in')?.textContent).toBe('94.7 MB');
101	    expect(container.querySelector('#metrics-stats-avg-in')?.textContent).toBe('332.4 kBps');
102	    expect(container.querySelector('#metrics-stats-latest-in')?.textContent).toBe('0 Bps');
103	    expect(container.querySelector('#metrics-stats-total-out')?.textContent).toBe('4.1 MB');
104	    expect(container.querySelector('#metrics-stats-avg-out')?.textContent).toBe('14.3 kBps');
105	    expect(container.querySelector('#metrics-stats-latest-out')?.textContent).toBe('0 Bps');
106	  });
107	
108	  it('should render edge metrics a->b', async () => {
109	    const edge = getEdge();
110	    const { container } = render(
111	      <ElementPanelMetrics
112	        metricType={mocks.metricType}
113	        metrics={mocks.metrics}
114	        aData={edge.getSource().getData()}
115	        bData={edge.getTarget().getData()}
116	        truncateLength={TruncateLength.M}
117	        isGroup={false}
118	      />
119	    );
120	    await waitFor(() => {
121	      expect(container.querySelector('#metrics-stats-total-in')).toBeTruthy();
122	    });
123	    expect(container.querySelector('#metrics-stats-total-in')?.textContent).toBe('1.1 MB');
124	    expect(container.querySelector('#metrics-stats-avg-in')?.textContent).toBe('3.9 kBps');
125	    expect(container.querySelector('#metrics-stats-total-out')?.textContent).toBe('4.5 MB');
126	    expect(container.querySelector('#metrics-stats-avg-out')?.textContent).toBe('15.9 kBps');
127	  });
128	});

